import { NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';
import webpush from 'web-push';

const prisma = new PrismaClient();

// Configure web-push with your VAPID keys
webpush.setVapidDetails(
  process.env.VAPID_SUBJECT || 'mailto:admin@whenisdue.com',
  process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY as string,
  process.env.VAPID_PRIVATE_KEY as string
);

export async function POST(request: Request) {
  try {
    // 1. In a real app, you would secure this route so only admins/system can call it.
    // For now, we are just testing the payload delivery.
    const body = await request.json();
    const alertMessage = body.message || 'A verified schedule shift has occurred.';

    // 2. Fetch all ACTIVE subscriptions from the database
    const subscriptions = await prisma.pushSubscription.findMany({
      where: { status: 'ACTIVE' }
    });

    if (subscriptions.length === 0) {
      return NextResponse.json({ message: 'No active subscriptions found.' }, { status: 200 });
    }

    // 3. Prepare the Push Payload (Must be under 4KB per Architect's rules)
    const payload = JSON.stringify({
      title: 'WhenIsDue Authority Update',
      body: alertMessage,
      url: '/series/ssa-ssdi-payments'
    });

    // 4. Send the push to all subscribers
    const sendPromises = subscriptions.map(async (sub) => {
      const pushSubscription = {
        endpoint: sub.endpoint,
        keys: {
          p256dh: sub.p256dh,
          auth: sub.auth,
        },
      };

      try {
        await webpush.sendNotification(pushSubscription, payload);
        console.log(`Push sent successfully to ${sub.id}`);
      } catch (error: any) {
        console.error(`Failed to send to ${sub.id}:`, error);
        // If the browser revoked the permission (410), we mark it as REVOKED in our DB
        if (error.statusCode === 410 || error.statusCode === 404) {
          await prisma.pushSubscription.update({
            where: { id: sub.id },
            data: { status: 'REVOKED', active: false, revokedAt: new Date() }
          });
        }
      }
    });

    await Promise.all(sendPromises);

    return NextResponse.json({ success: true, sentCount: subscriptions.length }, { status: 200 });

  } catch (error) {
    console.error('Broadcast error:', error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}